const incoming = ($json && typeof $json === 'object') ? $json : {};
const root = incoming.body && typeof incoming.body === 'object' && Object.keys(incoming.body).length
  ? incoming.body
  : incoming;

const CR = String.fromCharCode(13);

function pickFirst(...vals) {
  for (const v of vals) {
    if (v === undefined || v === null) continue;
    const str = typeof v === 'string' ? v.trim() : v;
    if (typeof str === 'string' && str.length === 0) continue;
    return str;
  }
  return undefined;
}

function toCleanString(value) {
  if (value === undefined || value === null) return '';
  if (typeof value === 'string') {
    const normalized = value.split(CR).join(' ');
    return normalized.replace(/\s+/g, ' ').trim();
  }
  if (typeof value === 'object') {
    try { return JSON.stringify(value); } catch { return String(value); }
  }
  return String(value);
}

function safeParseObject(value) {
  if (value === undefined || value === null) return null;
  if (typeof value === 'object' && !Array.isArray(value)) return value;
  if (typeof value === 'string') {
    const trimmed = value.trim();
    if (!trimmed) return null;
    try {
      const parsed = JSON.parse(trimmed);
      if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) return parsed;
    } catch {}
  }
  return null;
}

function clampWordCount(value, fallback = 600) {
  if (!Number.isFinite(value)) return fallback;
  return Math.max(120, Math.min(1600, Math.round(value)));
}

function normalizeUrl(value) {
  if (!value || typeof value !== 'string') return '';
  return value.trim().replace(/\/+$/, '');
}

function parseIdList(value) {
  if (!value) return [];
  if (Array.isArray(value)) {
    return value.map(v => String(v)).filter(Boolean);
  }
  if (typeof value === 'string') {
    try {
      const parsed = JSON.parse(value);
      if (Array.isArray(parsed)) {
        return parsed.map(v => String(v)).filter(Boolean);
      }
    } catch {}
    return value
      .split(/[\s,]+/)
      .map(v => v.trim())
      .filter(Boolean);
  }
  return [];
}

const workflowId = pickFirst(root.workflow_id, root.workflowId, 'flow_creative_script');
const workflowName = pickFirst(root.workflow_name, root.workflowName, '首页智能创作');
const taskId = pickFirst(root.task_id, root.taskId, root.replication_id, root.replicationId);
if (!taskId) {
  throw new Error('task_id is required');
}
const userId = pickFirst(root.user_id, root.userId);
if (!userId) {
  throw new Error('user_id is required');
}
const ideaText = toCleanString(pickFirst(root.idea_text, root.ideaText, root.text, root.content, root.topic, root.prompt));
if (!ideaText) {
  throw new Error('idea_text is required');
}
const requestedWordCount = clampWordCount(Number(pickFirst(root.word_count, root.wordCount, root.target_word_count, root.targetWordCount)));
const appUrl = normalizeUrl(pickFirst(root.app_url, root.appUrl, root.base_url, root.baseUrl, ''));
const callbackUrlRaw = pickFirst(root.callback_url, root.callbackUrl, '');
const callbackUrl = callbackUrlRaw || (appUrl ? `${appUrl}/api/webhook/replication/script` : '');

return [{
  json: {
    task_id: taskId,
    replication_id: pickFirst(root.replication_id, root.replicationId, taskId),
    user_id: userId,
    idea_text: ideaText,
    idea_summary: ideaText.slice(0, 160),
    target_word_count: requestedWordCount,
    workflow_id: workflowId,
    workflow_name: workflowName,
    api_key: pickFirst(root.api_key, root.apiKey, ''),
    callback_url: callbackUrl,
    app_url: appUrl,
    admin_token: pickFirst(root.admin_token, root.adminToken, ''),
    source: pickFirst(root.source, 'creative_workspace'),
    tenant: pickFirst(root.tenant, ''),
    style_rules: safeParseObject(root.style_rules ?? root.styleRules ?? null),
    history_doc_ids: parseIdList(root.history_doc_ids ?? root.historyDocIds),
    story_ids: parseIdList(root.story_ids ?? root.storyIds),
    style_ids: parseIdList(root.style_ids ?? root.styleIds),
    raw_body: root
  }
}];

const input = $json || {};
const adminToken = typeof input.admin_token === 'string' ? input.admin_token.trim() : '';
const appUrl = typeof input.app_url === 'string' ? input.app_url.trim() : '';
const userId = input.user_id;

function ensureArray(value) {
  if (Array.isArray(value)) return value;
  if (value === undefined || value === null) return [];
  return [value];
}

function limitArray(arr, limit) {
  return arr.slice(0, limit);
}

function normalizeText(value, max = 400) {
  if (value === undefined || value === null) return '';
  const str = String(value).replace(/\s+/g, ' ').trim();
  return str.length > max ? str.slice(0, max) + '…' : str;
}

async function fetchUserStyle() {
  if (!adminToken || !appUrl || !userId) {
    return {
      source: null,
      hasData: false,
      isInsufficient: true,
      docCount: 0,
      caseCount: 0,
      styleSummaries: [],
      writingBlocks: [],
      caseBanks: [],
      rawTextExcerpts: []
    };
  }
  try {
    const response = await $helpers.httpRequest({
      method: 'GET',
      url: `${appUrl}/api/internal/user-style`,
      qs: { user_id: userId },
      headers: { 'x-admin-token': adminToken },
      json: true,
      timeout: 20000
    });
    const data = response?.data || {};
    const styleSummaries = limitArray(ensureArray(data.styleSummaries).map((entry) => ({
      docTitle: normalizeText(entry?.docTitle || entry?.title || ''),
      domain: normalizeText(entry?.domain || entry?.domain_inference || ''),
      tone: normalizeText(entry?.tone || entry?.tone_profile || ''),
      keyMoves: normalizeText(entry?.key_moves || entry?.keyMoves || entry?.punchline || ''),
      raw: entry
    })), 4);

    const writingBlocks = limitArray(ensureArray(data.writingBlocks).map((entry) => ({
      label: normalizeText(entry?.label || entry?.purpose || ''),
      pattern: normalizeText(entry?.pattern || entry?.template || entry?.text || ''),
      raw: entry
    })), 6);

    const caseBanks = limitArray(ensureArray(data.caseBanks).map((entry) => ({
      id: entry?.id || null,
      type: normalizeText(entry?.type || entry?.cardType || ''),
      score: entry?.score ?? null,
      risk: entry?.risk || entry?.riskLevel || null,
      raw_text: normalizeText(entry?.raw_text || entry?.text || entry?.content || '', 320),
      raw: entry
    })), 6);

    const rawTextExcerpts = limitArray(ensureArray(data.rawTextExcerpts).map((entry) => ({
      docTitle: normalizeText(entry?.docTitle || ''),
      text: normalizeText(entry?.text || '', 320)
    })), 4);

    return {
      source: data.source || null,
      hasData: data.hasData === true,
      isInsufficient: data.isInsufficient === true,
      docCount: Number(data.docCount || 0),
      caseCount: Number(data.caseCount || 0),
      styleSummaries,
      writingBlocks,
      caseBanks,
      rawTextExcerpts
    };
  } catch (error) {
    return {
      source: null,
      hasData: false,
      isInsufficient: true,
      docCount: 0,
      caseCount: 0,
      styleSummaries: [],
      writingBlocks: [],
      caseBanks: [],
      rawTextExcerpts: [],
      fetchError: error?.message || String(error)
    };
  }
}

const styleContext = await fetchUserStyle();

return [{
  json: {
    ...input,
    style_context: styleContext
  }
}];

const input = $json || {};
const style = input.style_context || {};

function ensureArray(value) {
  if (Array.isArray(value)) return value;
  if (value === undefined || value === null) return [];
  return [value];
}

function summarizeList(label, items, pick) {
  if (!items.length) return '';
  const lines = items
    .map((item, idx) => `${idx + 1}. ${pick(item)}`.trim())
    .filter(Boolean);
  if (!lines.length) return '';
  return `${label}:
- ` + lines.join('
- ');
}

const summaryParts = [];
if (style.source) summaryParts.push(`来源：${style.source}`);
summaryParts.push(`样本文档：${style.docCount || 0} 篇`);
summaryParts.push(`案例片段：${style.caseCount || 0} 条`);
if (style.isInsufficient) summaryParts.push('⚠️ 历史文案偏少，建议补充');

const summaries = summarizeList('风格提炼', ensureArray(style.styleSummaries), (item) => {
  const domain = item.domain || item.domain_inference || '';
  const tone = item.tone || item.tone_profile || '';
  const moves = item.keyMoves || item.key_moves || '';
  return `${item.docTitle || ''}｜领域：${domain}｜口吻：${tone}｜招式：${moves}`
    .replace(/\s+/g, ' ')
    .trim();
});
if (summaries) summaryParts.push(summaries);

const blockSummary = summarizeList('结构模板', ensureArray(style.writingBlocks), (item) => {
  return `${item.label || item.purpose || ''} → ${item.pattern || item.template || item.text || ''}`
    .replace(/\s+/g, ' ')
    .trim();
});
if (blockSummary) summaryParts.push(blockSummary);

const caseSummary = summarizeList('案例语料', ensureArray(style.rawTextExcerpts), (item) => {
  return `${item.docTitle || ''}: ${item.text || ''}`.trim();
});
if (caseSummary) summaryParts.push(caseSummary);

const styleSummaryText = summaryParts.join('

');

const planPayload = {
  idea: input.idea_text,
  target_word_count: input.target_word_count,
  style_rules: input.style_rules,
  style_context: style,
  warnings: {
    insufficient_history: style.isInsufficient === true,
    fetch_error: style.fetchError || null
  }
};

return [{
  json: {
    ...input,
    plan_payload: planPayload,
    style_summary_text: styleSummaryText,
    history_warning: style.isInsufficient === true
  }
}];

