  if (s.startsWith('```')) {
    s = s.replace(/^```[a-zA-Z]*
?/, '').replace(/```$/, '').trim();
  }
  return s;
}
function extractJsonObjectString(s) {
  s = String(s ?? '');
  const first = s.indexOf('{');
  const last = s.lastIndexOf('}');
  if (first === -1 || last === -1 || last <= first) return '';
  return s.slice(first, last + 1);
}
function safeParseJson(raw) {
  if (raw == null) return {};
  if (typeof raw === 'object') return raw;
  let text = stripFence(raw);
  if (!text.trim().startsWith('{')) {
    const cut = extractJsonObjectString(text);
    if (cut) text = cut;
  }
  try {
    return JSON.parse(text);
  } catch (err) {
    const cut = extractJsonObjectString(text);
    if (cut && cut !== text) {
      try { return JSON.parse(cut); } catch {}
    }
    throw new Error('无法解析策划结果 JSON');
  }
}
const raw = $json.output ?? $json.result ?? $json.text ?? $json.content ?? $json;
const plan = safeParseJson(raw);
return [{ json: { plan } }];

