const context = $('构建创作上下文').item.json;
const raw = $json.output ?? $json.result ?? $json.text ?? $json.content ?? $json;
const obj = safeParseJson(raw);
const script = String(obj.script_content ?? obj.content ?? obj.text ?? '').trim();
const title = String(obj.title ?? '').trim() || context.idea_summary?.slice(0, 18) || '智能创作洞察';
