  json: {
    title,
    script_content: script,
    duration_estimate: durationEstimate,
    viral_logic: viralLogic,
    style_applied: styleApplied,
    needs_more_history: needsMore,
    data_suggestion: dataSuggestion,
    hashtags
  }
}];

